    String apname=request.getParameter("a");

    //check if user is a tab admin
    if(apname==null || user==null || !user.ifGroupManager(apname)) {
        out.println("No access right for "+user.getUserId());
        return;
    }

    //retrieve the APIEntry
    int emailNodeId= Encoder.parseInt(request.getParameter("emailNodeId"), Const.NONODE);
    if(emailNodeId==Const.NONODE){
        out.println("Incorrect parameters.");
        return;
    }

    User apiUser=new UserSuper(user.getUserId(),user.getUserName(apname));
    APIQuery aqUserReq =new APIQuery(apname,"/ragic-setup",10);
    aqUserReq.setUpdateMode();
    aqUserReq.setUser(apiUser);
    APIEntry e= aqUserReq.getAPIEntry(emailNodeId);
    if(e==null){
        out.println("User update request "+emailNodeId+" deleted.");
        return;
    }

    //below are messages more likely to be seen by users
    //check req status
    String reqStatus=e.getFieldValue(DConst.USER_REQ_STATUS);
    if(!"Draft".equals(reqStatus)){
        out.println(bundle.getString("userUpdateReqNoExecute")+" ("+reqStatus+")");
        return;
    }

    //check the group that he is trying to add this user to
    String email=e.getFieldValue(DConst.USER_REQ_EMAIL);
    List<String> groups=e.getFieldValues(DConst.USER_REQ_USERGROUPS);
    for(String groupName:groups){
        UserGroup group=Account.getInstance(apname).getUserGroup(groupName.toUpperCase());
        if(group==null) continue;
        if(!group.isGroupAdmin(user.getUserId()) && !user.ifApManager(apname)){
            out.println(bundle.getString("userUpdateReqNotGroupAdmin")+" <b>"+groupName+"</b>.");
            return;
        }
    }

    //check if this is a create and user already exists
    String requestType=e.getFieldValue(DConst.USER_REQ_TYPE);
    boolean ifExternal="External".equals(e.getFieldValue(DConst.USER_REQ_IF_EXTERNAL));
    APIQuery aquser=new APIQuery(apname,"/ragic-setup",ifExternal?5:1);
    aquser.setUpdateMode();
    aquser.setUser(apiUser);
    aquser.addFilter(DConst.USER_USERID_EMAIL, NUIFilter.SOR_EQ,email);
    APIEntry foundEntry=aquser.getAPIResult();
    ScriptResponse sr=null;
    if("Create".equals(requestType)){
        if(foundEntry!=null){
            out.println(bundle.getString("userUpdateReqUserExists"));
            return;
        }
        //check if has enough license
        if(!Account.getInstance(apname).ifCanAddUser()){
            out.println(bundle.getString("userUpdateReqLicense",new Object[]{Account.getInstance(apname).getMaxUser()}));
            return;
        }
        //make the update
        APIEntry insert=aquser.insertAPIEntry();
        insert.setFieldValue(DConst.USER_USERID_EMAIL,email);
        insert.setFieldValue(DConst.USER_NAME,e.getFieldValue(DConst.USER_REQ_FULLNAME));
        insert.setFieldValue(DConst.USER_EMPLOYEE_NUMBER,e.getFieldValue(DConst.USER_REQ_EMPLOYEE_NUM));
        insert.setFieldValue(DConst.USER_TITLE,e.getFieldValue(DConst.USER_REQ_TITLE));
        insert.setFieldValue(DConst.USER_COMPANY,e.getFieldValue(DConst.USER_REQ_COMPANY));
        insert.setFieldValue(DConst.USER_DIVISION,e.getFieldValue(DConst.USER_REQ_DIVISION));
        insert.setFieldValue(DConst.USER_DEPARTMENT,e.getFieldValue(DConst.USER_REQ_DEPARTMENT));
        insert.setFieldValue(DConst.USER_DIRECT_SUPERVISOR,e.getFieldValue(DConst.USER_REQ_SUPERVISOR));
        insert.setFieldValue(DConst.USER_DEPUTY,e.getFieldValue(DConst.USER_REQ_DEPUTY));
        insert.setFieldValue(DConst.USER_SAML_NAMEID,e.getFieldValue(DConst.USER_SAML_NAMEID));
        insert.setFieldValue(DConst.USER_EXTERNAL_TYPE,e.getFieldValue(DConst.USER_REQ_IF_EXTERNAL));
        insert.setFieldValue(DConst.USER_EXTENSION,e.getFieldValue(DConst.USER_REQ_EXTENSION));
        insert.setFieldValue(DConst.USER_FAX,e.getFieldValue(DConst.USER_REQ_FAX));
        insert.setFieldValue(DConst.USER_MOBILE,e.getFieldValue(DConst.USER_REQ_MOBILE));
        insert.setFieldValue(DConst.USER_MAILING_ADDRESS,e.getFieldValue(DConst.USER_REQ_MAILING_ADDRESS));
        insert.setFieldValue(DConst.USER_SIGNATURE_IMAGE,e.getFieldValue(DConst.USER_REQ_SIGNATURE));
        insert.setFieldValue(DConst.USER_PICTURE,e.getFieldValue(DConst.USER_REQ_PICTURE));
        insert.setFieldValue(DConst.USER_STATUS,"NORMAL");

        //insert.setFieldValue(DConst.USER_GROUP,Const.G_USER);//[BugId:13898]
        for(String groupName:groups){
            insert.setFieldValue(DConst.USER_GROUP,groupName,true);
        }

        insert.setFieldValue(DConst.USER_REQ_SYSTEM_LOG,"Created by req id:"+e.getFieldValue(DConst.USER_REQ_ID));
        sr=insert.save(apiUser,bundle);
    }
    //check if this is an update and user not exist
    else if("Update".equals(requestType) || "Suspend".equals(requestType)){
        if(foundEntry==null){
            out.println(bundle.getString("userUpdateReqNoUser")+": "+email);
            return;
        }

        //check if the user is in your group
        List<String> foundEntryGroups=foundEntry.getFieldValues(DConst.USER_GROUP);
        boolean hasMyGroup=false;
        boolean isSysAdmin=false;
        for(String groupName:foundEntryGroups){
            UserGroup group=Account.getInstance(apname).getUserGroup(groupName);
            if(group!=null){
                if(group.isGroupAdmin(user.getUserId())){
                    hasMyGroup=true;
                }
                if(group.isSysadmin()){
                    isSysAdmin=true;
                }
            }
        }
        if(!hasMyGroup){
            out.println(bundle.getString("userUpdateReqNotYourGroup",new Object[]{email}));
            return;
        }
        if(isSysAdmin){
            out.println(bundle.getString("userUpdateReqNoSysadmin",new Object[]{email}));
            return;
        }

        //make the update
        if("Suspend".equals(requestType)) {
            foundEntry.setFieldValue(DConst.USER_STATUS,"SUSPENDED");
        }
        else{
            //update only if req field is not empty
            if(!e.getFieldValue(DConst.USER_REQ_FULLNAME).isEmpty()) foundEntry.setFieldValue(DConst.USER_NAME,e.getFieldValue(DConst.USER_REQ_FULLNAME));
            if(!e.getFieldValue(DConst.USER_REQ_EMPLOYEE_NUM).isEmpty()) foundEntry.setFieldValue(DConst.USER_EMPLOYEE_NUMBER,e.getFieldValue(DConst.USER_REQ_EMPLOYEE_NUM));
            if(!e.getFieldValue(DConst.USER_REQ_TITLE).isEmpty()) foundEntry.setFieldValue(DConst.USER_TITLE,e.getFieldValue(DConst.USER_REQ_TITLE));
            if(!e.getFieldValue(DConst.USER_REQ_COMPANY).isEmpty()) foundEntry.setFieldValue(DConst.USER_COMPANY,e.getFieldValue(DConst.USER_REQ_COMPANY));
            if(!e.getFieldValue(DConst.USER_REQ_DIVISION).isEmpty()) foundEntry.setFieldValue(DConst.USER_DIVISION,e.getFieldValue(DConst.USER_REQ_DIVISION));
            if(!e.getFieldValue(DConst.USER_REQ_DEPARTMENT).isEmpty()) foundEntry.setFieldValue(DConst.USER_DEPARTMENT,e.getFieldValue(DConst.USER_REQ_DEPARTMENT));
            if(!e.getFieldValue(DConst.USER_REQ_SUPERVISOR).isEmpty()) foundEntry.setFieldValue(DConst.USER_DIRECT_SUPERVISOR,e.getFieldValue(DConst.USER_REQ_SUPERVISOR));
            if(!e.getFieldValue(DConst.USER_REQ_DEPUTY).isEmpty()) foundEntry.setFieldValue(DConst.USER_DEPUTY,e.getFieldValue(DConst.USER_REQ_DEPUTY));
            if(!e.getFieldValue(DConst.USER_REQ_IF_EXTERNAL).isEmpty()) foundEntry.setFieldValue(DConst.USER_EXTERNAL_TYPE,e.getFieldValue(DConst.USER_REQ_IF_EXTERNAL));
            if(!e.getFieldValue(DConst.USER_REQ_EXTENSION).isEmpty()) foundEntry.setFieldValue(DConst.USER_EXTENSION,e.getFieldValue(DConst.USER_REQ_EXTENSION));
            if(!e.getFieldValue(DConst.USER_REQ_FAX).isEmpty()) foundEntry.setFieldValue(DConst.USER_FAX,e.getFieldValue(DConst.USER_REQ_FAX));
            if(!e.getFieldValue(DConst.USER_REQ_MOBILE).isEmpty()) foundEntry.setFieldValue(DConst.USER_MOBILE,e.getFieldValue(DConst.USER_REQ_MOBILE));
            if(!e.getFieldValue(DConst.USER_REQ_MAILING_ADDRESS).isEmpty()) foundEntry.setFieldValue(DConst.USER_MAILING_ADDRESS,e.getFieldValue(DConst.USER_REQ_MAILING_ADDRESS));
            if(!e.getFieldValue(DConst.USER_REQ_SIGNATURE).isEmpty()) foundEntry.setFieldValue(DConst.USER_SIGNATURE_IMAGE,e.getFieldValue(DConst.USER_REQ_SIGNATURE));
            if(!e.getFieldValue(DConst.USER_REQ_PICTURE).isEmpty()) foundEntry.setFieldValue(DConst.USER_PICTURE,e.getFieldValue(DConst.USER_REQ_PICTURE));
            if(!e.getFieldValue(DConst.USER_REQ_USERGROUPS).isEmpty()){
                for(String groupName:groups){
                    foundEntry.setFieldValue(DConst.USER_GROUP,groupName,true);
                }
            }
            foundEntry.setFieldValue(DConst.USER_STATUS,"NORMAL");
        }

        String previousLog=foundEntry.getFieldValue(DConst.USER_REQ_SYSTEM_LOG);
        foundEntry.setFieldValue(DConst.USER_REQ_SYSTEM_LOG,previousLog+"\nUpdated by req id:"+e.getFieldValue(DConst.USER_REQ_ID));

        sr=foundEntry.save(apiUser,bundle);
    }

    //request failed
    if(sr==null){
        out.println(bundle.getString("userUpdateReqNoExecute")+"(not executed)");
        return;
    }
    if(!sr.ifExec()){
        out.println(sr.getMessage());
        return;
    }

    //log result in req form
    e.setFieldValue(DConst.USER_REQ_STATUS,"Completed");
    e.setFieldValue(DConst.USER_REQ_SYSTEM_LOG,requestType+" completed on "+Encoder.formatAsStandardDate(new Date(),true));
    e.lock();
    e.save(user,bundle);


      out.write("<script>opener.document.getElementById('bReload').click();window.close();</script>");
